@push('styles')
<style>
.scanner-frame.is-active{border-style:solid!important;box-shadow:0 0 0 4px rgba(25,135,84,.08);animation:scannerPulse 1.6s ease-in-out infinite}.border-dashed{border-style:dashed!important}.scanner-reader{width:100%;aspect-ratio:9/16;min-height:420px;border-radius:1rem;overflow:hidden;background:#0f172a;position:relative}.scanner-reader video,.scanner-reader canvas{width:100%!important;height:100%!important;object-fit:contain}.scanner-reader video{background:#0f172a}.scanner-flash{position:absolute;inset:0;background:rgba(25,135,84,.35);opacity:0;pointer-events:none;z-index:5}.scanner-flash.is-visible{animation:scanFlash 420ms ease-out}#resultBorder.is-success{border-color:#198754!important}#resultBorder.is-danger{border-color:#dc3545!important}#historyList .list-group-item{border-left:0;border-right:0;padding-left:0;padding-right:0;background:transparent}#historyList .history-row{background:rgba(15,23,42,.03);border-radius:.85rem;transition:background-color .2s ease,transform .2s ease}#historyList .history-row:hover{background:rgba(15,23,42,.06);transform:translateY(-1px)}@keyframes scannerPulse{0%,100%{box-shadow:0 0 0 0 rgba(25,135,84,.12)}50%{box-shadow:0 0 0 8px rgba(25,135,84,.02)}}@keyframes scanFlash{0%{opacity:0}15%{opacity:1}100%{opacity:0}}@media (max-width:575.98px){.scanner-actions .btn{width:100%}.scanner-reader{min-height:320px}}
</style>
